{
  "title": "फ़ंक्शनों के साथ मूव सेमैंटिक्स",
  "group": "स्वामित्व",
  "options": [
    {
      "text": "दोनों पंक्तियाँ प्रिंट करता है",
      "hint": "सोचें कि फ़ंक्शन में पास करने के बाद 'wisdom' का क्या होता है"
    },
    {
      "text": "केवल पहली पंक्ति प्रिंट करता है",
      "hint": "कोड रनटाइम तक पहुँचने के लिए कंपाइल भी नहीं होगा"
    },
    {
      "text": "कंपाइलेशन त्रुटि"
    },
    {
      "text": "रनटाइम त्रुटि",
      "hint": "Rust के स्वामित्व नियम कंपाइल समय पर लागू होते हैं"
    }
  ],
  "questionProse": [
    "जब आप यह कोड चलाते हैं तो क्या होता है? स्वामित्व हस्तांतरण के बारे में सोचें:"
  ],
  "explanationProse": [
    "कोड कंपाइल नहीं होता क्योंकि `wisdom` का स्वामित्व `take_knowledge` में स्थानांतरित हो गया और इसलिए बाद में इसका उपयोग नहीं किया जा सकता।\n\n      इस समस्या को ठीक करने के तीन तरीके हैं:\n\n      1. संदर्भ द्वारा पास करें (मान उधार लें):",
    "2. मान को क्लोन करें (एक नई प्रतिलिपि बनाएँ):",
    "3. फ़ंक्शन से स्वामित्व वापस करें:",
    "प्रत्येक दृष्टिकोण के अलग-अलग उपयोग के मामले हैं:\n      - संदर्भ: सबसे कुशल, लेकिन जीवनकाल प्रबंधन की आवश्यकता\n      - क्लोनिंग: सरल लेकिन संभावित रूप से महंगा\n      - स्वामित्व वापस करना: मानों को रूपांतरित करने के लिए उपयोगी\n\n      सर्वोत्तम अभ्यास: जब तक स्वामित्व हस्तांतरण की आवश्यकता न हो, संदर्भ का उपयोग करें।"
  ]
}
